import React, { useState, useRef } from 'react';
import springLogo from '../../assets/with_Spring_removebg.png';
import useClickOutside from '../../hooks/useClickOutside';

const UserHeader = () => {
    const [isDropdownOpen, setIsDropdownOpen] = useState(false);
    const dropdownRef = useRef(null);

    useClickOutside(dropdownRef, () => {
        if (isDropdownOpen) setIsDropdownOpen(false);
    });

    const toggleDropdown = () => setIsDropdownOpen(!isDropdownOpen);

    return (
        <header className="w-full bg-sky-400 py-4">
            <div className="container mx-auto px-4 flex items-center justify-between">
                <img src={springLogo} alt="Spring 로고" className="h-12 w-12 object-contain"/>
                <div className="flex-grow max-w-3xl mx-4">
                    <form className="flex items-center">
                        <div className="relative flex-grow" ref={dropdownRef}>
                            <button 
                                type="button"
                                onClick={toggleDropdown}
                                className="absolute left-0 top-0 z-10 inline-flex h-full items-center py-2.5 px-4 text-sm font-medium text-gray-700 bg-gray-100 rounded-l-lg border border-gray-300 hover:bg-gray-200 focus:ring-4 focus:outline-none focus:ring-gray-100"
                            >
                                통합검색
                                <svg className="w-2.5 h-2.5 ms-2.5" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 10 6">
                                    <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="m1 1 4 4 4-4"/>
                                </svg>
                            </button>
                            {isDropdownOpen && (
                                <div className="absolute left-0 mt-12 w-44 bg-white divide-y divide-gray-100 rounded-lg shadow z-20">
                                    <ul className="py-2 text-sm text-gray-700">
                                        <li>
                                            <button type="button" className="block px-4 py-2 hover:bg-gray-100 w-full text-left">Mockups</button>
                                        </li>
                                        <li>
                                            <button type="button" className="block px-4 py-2 hover:bg-gray-100 w-full text-left">Templates</button>
                                        </li>
                                        <li>
                                            <button type="button" className="block px-4 py-2 hover:bg-gray-100 w-full text-left">Design</button>
                                        </li>
                                        <li>
                                            <button type="button" className="block px-4 py-2 hover:bg-gray-100 w-full text-left">Logos</button>
                                        </li>
                                    </ul>
                                </div>
                            )}
                            <input type="search" id="search-dropdown" className="block p-2.5 w-full z-20 text-sm text-gray-900 bg-gray-50 rounded-lg border border-gray-300 focus:ring-blue-500 focus:border-blue-500 pl-32" placeholder="Search Mockups, Logos, Design Templates..." required />
                            <button type="submit" className="absolute top-0 right-0 p-2.5 text-sm font-medium h-full text-white bg-blue-700 rounded-r-lg border border-blue-700 hover:bg-blue-800 focus:ring-4 focus:outline-none focus:ring-blue-300">
                                <svg className="w-4 h-4" aria-hidden="true" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 20 20">
                                    <path stroke="currentColor" strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="m19 19-4-4m0-7A7 7 0 1 1 1 8a7 7 0 0 1 14 0Z"/>
                                </svg>
                                <span className="sr-only">Search</span>
                            </button>
                        </div>
                    </form>
                </div>
            </div>
        </header>
    );
}

export default UserHeader;
